// Reduz cada item de feed ao mínimo necessário e filtra pelos últimos N dias (otimização de tokens)
const items = $input.all();
const diasAtras = $('Parâmetros da Newsletter').first().json.diasAtras || 2;
const limite = new Date();
limite.setDate(limite.getDate() - diasAtras);

const vistos = new Set();
const resultado = [];

for (const item of items) {
  const j = item.json;
  const dataPub = j.pubDate || j.isoDate || j.publishedDate;
  const data = dataPub ? new Date(dataPub) : null;
  if (!data || isNaN(data.getTime()) || data < limite) continue;

  const link = j.link || j.guid || '';
  if (!link || vistos.has(link)) continue;
  vistos.add(link);

  const textoBase = (j.contentSnippet || j.summary || j.content || '')
    .replace(/<[^>]*>/g, '')
    .trim();

  let fonte = j.creator || j.author || '';
  if (!fonte && link) {
    try { fonte = new URL(link).hostname; } catch (e) { fonte = ''; }
  }

  resultado.push({
    json: {
      titulo: (j.title || '').trim(),
      link,
      fonte,
      dataPublicacao: data.toISOString(),
      resumoOriginal: textoBase.slice(0, 250)
    }
  });
}

resultado.sort((a, b) => new Date(b.json.dataPublicacao) - new Date(a.json.dataPublicacao));
return resultado.slice(0, 40);

// Monta uma lista indexada e compacta para a LLM de seleção (menos tokens = índice numérico + título curto)
const noticias = $json.noticias;
const listaIndexada = noticias
  .map((n, i) => `${i}. [${n.titulo}] (Fonte: ${n.fonte}) - ${n.resumoOriginal}`)
  .join(' | ');

return [{ json: { noticias, listaIndexada } }];

// Extrai os índices retornados pela LLM de seleção e reconstrói a lista completa das notícias escolhidas
const resposta = $input.first().json.choices[0].message.content;
let indices = [];
try {
  const match = resposta.match(/\[[\s\d,]*\]/);
  indices = JSON.parse(match ? match[0] : resposta);
} catch (e) {
  indices = [];
}

const noticias = $('Preparar Prompt de Seleção').first().json.noticias;
const selecionadas = indices
  .filter((i) => Number.isInteger(i) && noticias[i])
  .map((i) => noticias[i]);

return [{ json: { selecionadas } }];

// Extrai o texto final e divide em blocos de até 4096 caracteres (limite do Telegram)
const texto = $input.first().json.choices[0].message.content.trim();
const LIMITE = 4096;
const partes = [];
for (let i = 0; i < texto.length; i += LIMITE) {
  partes.push(texto.slice(i, i + LIMITE));
}
return partes.map((p) => ({ json: { mensagem: p } }));
